insight.code_example:
mutation {
  marketCreate(
    input: {
      name: "US Market"
      currencyCode: USD
      shippingSettings: {
        shippingOptions: [
          {
            name: "Ground"
            price: 10.00
          }
        ]
      }
    }
  ) {
    market {
      id
      name
      currencyCode
      shippingSettings {
        shippingOptions {
          name
          price
        }
      }
    }
  }
}
